320:             val name = Regex(""""tool_name"\s*:\s*"(\w+)"""").find(json)?.groupValues?.get(1)
321:             val args = Regex(""""arguments"\s*:\s*(\{[^}]+\})""").find(json)?.groupValues?.get(1)
322:             if (name != null && args != null) Pair(name, args) else null
323:         } catch (e: Exception) {
324:             null
325:         }
326:     }
327: 
328:     private fun emitStep(description: String, progress: Int) {
329:         // Only move forward — never let progress go backwards
330:         currentProgress = maxOf(currentProgress, progress).coerceIn(0, 99)
331:         listener.onUpdate(DeepCheckUpdate.Step(description, currentProgress))
332:     }
