334:     private fun emitEvidence(detail: String) {
335:         listener.onUpdate(
336:             DeepCheckUpdate.FoundEvidence(
337:                 EvidenceItem(
338:                     source = "Deep Check",
339:                     detail = detail,
340:                     severity = "HIGH"
341:                 )
342:             )
343:         )
