351:     private fun recordHistory(verdict: DeepCheckVerdict) {
352:         try {
353:             val hash = HashUtil.hashSms(smsSender, smsText)
354:             val verdictStr = when {
355:                 verdict.isScam -> "SCAM"
356:                 verdict.evidence.size >= 2 -> "SCAM"
357:                 verdict.evidence.isNotEmpty() -> "SUSPICIOUS"
358:                 else -> "SAFE"
359:             }
360:             val entry = HistoryEntry(
361:                 hash = hash,
362:                 verdict = verdictStr,
363:                 confidence = if (verdict.isScam) 0.85f else 0.5f,
364:                 timestamp = System.currentTimeMillis(),
365:                 evidenceCount = verdict.evidence.size
366:             )
367:             applicationScope.launch {
368:                 try {
369:                     withContext(dispatchers.io) { historyDao.insert(entry) }
370:                 } catch (e: Exception) {
371:                     Log.w("DeepCheck", "Failed to insert history entry", e)
372:                 }
373:             }
374:         } catch (e: Exception) {
375:             Log.w("DeepCheck", "Failed to record history", e)
376:         }
377:     }
