379:     private fun emitFallbackVerdict(llmContext: String? = null) {
380:         val verdict = if (evidenceList.size >= 2) "SCAM" else "SUSPICIOUS"
381:         val llmSummary = llmContext?.take(300)?.let { if (llmContext.length > 300) "$it..." else it }
382:         emitVerdict(
383:             DeepCheckVerdict(
384:                 isScam = verdict == "SCAM",
385:                 summary = llmSummary ?: if (verdict == "SCAM") context.getString(R.string.summary_scam) else context.getString(R.string.summary_suspicious),
386:                 threatType = null,
387:                 evidence = evidenceList.map {
