398:                         context.getString(R.string.action_caution),
399:                         context.getString(R.string.action_verify_org)
400:                     )
401:                 },
402:                 educationalExplanation = TextSanitizer.toParagraph(llmSummary ?: "")
403:             )
404:         )
405:     }
