407:     private suspend fun runRuleBasedAnalysis(llmContext: String? = null) {
408:         val toolExecutor = ToolExecutor(
409:             allowlistDao, historyDao, reputationDb, officialSites, proxyClient
410:         )
411:         val urls = com.smssentry.deepcheck.prefilter.FastPathFilter.extractUrls(smsText)
412:         val domains = com.smssentry.deepcheck.prefilter.FastPathFilter.extractDomains(urls)
413:         val urlsJson = urls.joinToString(",") { "\"$it\"" }
414: 
415:         emitStep("Checking sender reputation...", 55)
416:         val repResult = withTimeoutOrNull(DeepCheckConfig.TOOL_EXECUTION_TIMEOUT_MS) {
417:             withContext(dispatchers.io) {
418:                 toolExecutor.executeByName("offline_reputation_check", """{"urls":[$urlsJson]}""")
419:             }
420:         }
421:         if (repResult is ToolResult.Evidence) {
422:             evidenceList.add(repResult.message)
423:             emitEvidence(repResult.message)
424:         }
425: 
426:         if (domains.isNotEmpty()) {
427:             emitStep("Looking up domain registration...", 65)
428:             for (domain in domains.take(2)) {
429:                 if (isCancelled) return
430:                 val whoisResult = withTimeoutOrNull(DeepCheckConfig.TOOL_EXECUTION_TIMEOUT_MS) {
431:                     withContext(dispatchers.io) {
432:                         toolExecutor.executeByName("whois_lookup", """{"domain":"$domain"}""")
433:                     }
434:                 }
435:                 if (whoisResult is ToolResult.Evidence) {
436:                     evidenceList.add(whoisResult.message)
437:                     emitEvidence(whoisResult.message)
438:                 }
439:             }
440:         }
441: 
442:         emitStep("Analyzing brand impersonation...", 80)
443:         val mismatchResult = withTimeoutOrNull(DeepCheckConfig.TOOL_EXECUTION_TIMEOUT_MS) {
444:             withContext(dispatchers.io) {
445:                 toolExecutor.executeByName("brand_mismatch_check", """{"sms_text":"$smsText","urls":[$urlsJson]}""")
446:             }
447:         }
448:         if (mismatchResult is ToolResult.Evidence) {
449:             evidenceList.add(mismatchResult.message)
450:             emitEvidence(mismatchResult.message)
451:         }
452: 
453:         for (domain in domains.take(2)) {
454:             if (isCancelled) return
455:             val claimedEntity = officialSites.findMatchingBrand(smsText)
456:             if (claimedEntity != null) {
457:                 emitStep("Comparing with official $domain...", 90)
458:                 val compareResult = withTimeoutOrNull(DeepCheckConfig.TOOL_EXECUTION_TIMEOUT_MS) {
459:                     withContext(dispatchers.io) {
460:                         toolExecutor.executeByName("compare_official_site", """{"claimed_entity":"$claimedEntity","linked_domain":"$domain"}""")
461:                     }
462:                 }
463:                 if (compareResult is ToolResult.Evidence) {
464:                     evidenceList.add(compareResult.message)
465:                     emitEvidence(compareResult.message)
466:                 }
467:             }
468:         }
469: 
470:         emitFallbackVerdict(llmContext)
471:     }
